<span class="line">  <span class="token property">background</span><span class="token punctuation">:</span> <span class="token function">rgba</span><span class="token punctuation">(</span>234<span class="token punctuation">,</span> 234<span class="token punctuation">,</span> 240<span class="token punctuation">,</span> 0.42<span class="token punctuation">)</span><span class="token punctuation">;</span> <span class="token comment">/* 原 0.22 → 0.42 */</span></span>
